const net = require('net');
const inputData = $('Trigger').first().json;
const domain = inputData.domain;
const candidates = inputData.candidates || [];

// Parse DNS response — handle dns-json content-type wrapping
let dnsResp = $input.first().json;
if (!dnsResp.Answer && dnsResp.data && typeof dnsResp.data === 'string') {
  try { dnsResp = JSON.parse(dnsResp.data); } catch(e) {}
}

const answers = Array.isArray(dnsResp.Answer) ? dnsResp.Answer : [];
const mxRecords = answers
  .filter(a => a.type === 15)
  .sort((a, b) => {
    const pa = parseInt((a.data || '').split(' ')[0]) || 999;
    const pb = parseInt((b.data || '').split(' ')[0]) || 999;
    return pa - pb;
  })
  .map(a => (a.data || '').split(' ').slice(1).join(' ').replace(/\.$/, '').trim())
  .filter(Boolean);

if (!mxRecords.length || !domain) {
  return [{ json: { status: 'no_mx', is_catch_all: false, domain, mx_host: null, candidates: [] } }];
}

const mxHost = mxRecords[0];
const fakeEmail = 'xfake' + Math.random().toString(36).slice(2, 8) + '@' + domain;
// Fake probe goes FIRST — ensures it's always tested even if server closes early
const allEmails = [fakeEmail, ...candidates];

const smtpData = await new Promise((resolve) => {
  const rcptCodes = {};
  let buf = '';
  let step = 0;
  let idx = 0;
  let settled = false;

  function finish(val) {
    if (settled) return;
    settled = true;
    clearTimeout(timer);
    try { socket.destroy(); } catch(e) {}
    resolve(val);
  }

  const timer = setTimeout(() => finish({ error: 'timeout', rcptCodes }), 20000);
  const socket = net.connect({ host: mxHost, port: 25 });

  socket.on('data', (chunk) => {
    buf += chunk.toString();
    const lines = buf.split('\r\n');
    buf = lines.pop() || '';
    for (const line of lines) {
      if (!line) continue;
      const code = parseInt(line.slice(0, 3), 10);
      if (line[3] === '-') continue;
      if (step === 0 && code === 220) {
        socket.write('EHLO mf.local\r\n'); step = 1;
      } else if (step === 1 && code === 250) {
        socket.write('MAIL FROM:<vyhry-temu@seznam.cz>\r\n'); step = 2;
      } else if (step === 1) {
        finish({ error: 'ehlo_' + code, rcptCodes }); return;
      } else if (step === 2 && code === 250) {
        socket.write('RCPT TO:<' + allEmails[idx] + '>\r\n'); step = 3;
      } else if (step === 2) {
        finish({ error: 'mailfrom_' + code, rcptCodes }); return;
      } else if (step === 3) {
        rcptCodes[allEmails[idx]] = code;
        idx++;
        if (idx < allEmails.length) {
          socket.write('RCPT TO:<' + allEmails[idx] + '>\r\n');
        } else {
          socket.write('QUIT\r\n'); step = 4;
        }
      } else if (step === 4) {
        finish({ error: null, rcptCodes }); return;
      }
    }
  });

  socket.on('error', (e) => finish({ error: e.message, rcptCodes }));
  socket.on('close', () => finish({ error: null, rcptCodes }));
});

if (smtpData.error && !Object.keys(smtpData.rcptCodes).length) {
  return [{ json: { status: 'smtp_error', is_catch_all: true, domain, mx_host: mxHost, candidates: [] } }];
}

const r = smtpData.rcptCodes;
const fakeAccepted = r[fakeEmail] === 250;
const candidateResults = candidates.map(e => ({ email: e, accepted: r[e] === 250, code: r[e] || null }));
const anyAccepted = candidateResults.some(c => c.accepted);

// Catch-all detection:
// 1. Fake accepted — server accepts everything
// 2. All candidates accepted (even single) — suspicious
// 3. High acceptance ratio (>=60% of 3+ candidates) — deferred rejection signal
// 4. Partial SMTP data (connection dropped mid-stream) + some accepted — inconclusive
const acceptedCount = candidateResults.filter(c => c.accepted).length;
const allCandidatesAccepted = candidateResults.length >= 1 && candidateResults.every(c => c.accepted);
const highAcceptance = candidates.length >= 3 && (acceptedCount / candidates.length) >= 0.6;
const hasPartialData = allEmails.some(e => r[e] === undefined);
const is_catch_all = fakeAccepted || allCandidatesAccepted || highAcceptance || (hasPartialData && acceptedCount > 0);
const status = is_catch_all ? 'catch_all' : anyAccepted ? 'partial_match' : 'all_rejected';

return [{ json: { status, is_catch_all, domain, mx_host: mxHost, candidates: candidateResults } }];
